import React, { useState } from 'react';
import { Container, Row, Col, Button } from 'react-bootstrap';
import { AuthProvider, useAuth } from './context/AuthContext';
import Login from './components/Login';
import NavigationBar from './components/Navbar';
import Cart from './components/Cart';
import PartsSearch from './pages/PartsSearch';
import Checkout from './pages/Checkout';
import 'bootstrap/dist/css/bootstrap.min.css';
import './App.css';

function AppContent() {
  const { isAuthenticated } = useAuth();
  const [cartItems, setCartItems] = useState([]);
  const [showCheckout, setShowCheckout] = useState(false);
  const [orderSuccess, setOrderSuccess] = useState('');

  const addToCart = (part) => {
    setCartItems(prevItems => {
      const existingItem = prevItems.find(item => item.id === part.id);
      if (existingItem) {
        return prevItems.map(item =>
          item.id === part.id
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      }
      return [...prevItems, { ...part, quantity: 1 }];
    });
  };

  const removeFromCart = (partId) => {
    setCartItems(prevItems => prevItems.filter(item => item.id !== partId));
  };

  const clearCart = () => {
    setCartItems([]);
    setOrderSuccess('');
    setShowCheckout(false);
  };

  if (!isAuthenticated) {
    return <Login />;
  }

  return (
    <div className="App">
      <NavigationBar cartCount={cartItems.length} />

      <Container fluid className="main-content">
        {orderSuccess && (
          <div className="alert alert-success">
            {orderSuccess}
            <Button variant="outline-success" size="sm" className="ms-3" onClick={clearCart}>
              OK
            </Button>
          </div>
        )}

        <Row>
          <Col md={showCheckout ? 12 : 9}>
            {showCheckout ? (
              <div>
                <Button variant="outline-secondary" onClick={() => setShowCheckout(false)} className="mb-3">
                  ← Назад к поиску
                </Button>
                <Checkout 
                  cartItems={cartItems} 
                  onClearCart={() => {
                    clearCart();
                    setOrderSuccess('Заказ успешно создан!');
                  }} 
                />
              </div>
            ) : (
              <PartsSearch onAddToCart={addToCart} />
            )}
          </Col>

          {!showCheckout && (
            <Col md={3}>
              <Cart 
                items={cartItems}
                onRemoveItem={removeFromCart}
                onClearCart={clearCart}
              />
              {cartItems.length > 0 && (
                <button 
                  className="btn btn-success w-100 mt-2"
                  onClick={() => setShowCheckout(true)}
                >
                  📝 Оформить заказ
                </button>
              )}
            </Col>
          )}
        </Row>
      </Container>
    </div>
  );
}

function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

export default App;
